	public void UpdateState(PowerChargeState state)
	{
		if (state.On)
		{
			((BaseButton)OnButton).Pressed = true;
		}
		else
		{
			((BaseButton)OffButton).Pressed = true;
		}
		PowerLabel.Text = Loc.GetString("power-charge-window-power-label", new(string, object)[2]
		{
			("draw", state.PowerDraw),
			("max", state.PowerDrawMax)
		});
		((Control)PowerLabel).SetOnlyStyleClass(MathHelper.CloseTo((float)state.PowerDraw, (float)state.PowerDrawMax, 1E-07f) ? "Good" : "Caution");
		((Range)ChargeBar).Value = (int)state.Charge;
		ChargeText.Text = ((float)(int)state.Charge / 255f).ToString("P0");
		Label statusLabel = StatusLabel;
		statusLabel.Text = Loc.GetString(state.PowerStatus switch
		{
			PowerChargePowerStatus.Off => "power-charge-window-status-off", 
			PowerChargePowerStatus.Discharging => "power-charge-window-status-discharging", 
			PowerChargePowerStatus.Charging => "power-charge-window-status-charging", 
			PowerChargePowerStatus.FullyCharged => "power-charge-window-status-fully-charged", 
			_ => throw new ArgumentOutOfRangeException(), 
		});
		statusLabel = StatusLabel;
		((Control)statusLabel).SetOnlyStyleClass(state.PowerStatus switch
		{
			PowerChargePowerStatus.Off => "Danger", 
			PowerChargePowerStatus.Discharging => "Caution", 
			PowerChargePowerStatus.Charging => "Caution", 
			PowerChargePowerStatus.FullyCharged => "Good", 
			_ => throw new ArgumentOutOfRangeException(), 
		});
		EtaLabel.Text = ((state.EtaSeconds >= 0) ? Loc.GetString("power-charge-window-eta-value", new(string, object)[1] { ("left", TimeSpan.FromSeconds(state.EtaSeconds)) }) : Loc.GetString("power-charge-window-eta-none"));
		((Control)EtaLabel).SetOnlyStyleClass((state.EtaSeconds >= 0) ? "Caution" : "Disabled");
	}

